class EnterpriseEntity1Service:
    def __init__(self, repository, event_bus, cache):
        self.repository = repository
        self.event_bus = event_bus
        self.cache = cache

    async def create_entity(self, tenant_id: str, data: Dict[str, Any]) -> EnterpriseEntity1:
        logger.info(f'Creating EnterpriseEntity1 for tenant {tenant_id}')
        entity = EnterpriseEntity1(tenant_id=tenant_id)
        for key, value in data.items():
            if hasattr(entity, key):
                setattr(entity, key, value)
        entity.validate()
        await self.repository.save(entity)
        await self.event_bus.publish('Entity1Created', entity.to_dict())
        return entity

    async def get_entity(self, entity_id: str, tenant_id: str) -> Optional[EnterpriseEntity1]:
        cache_key = f'entity_1_{tenant_id}_{entity_id}'
        cached = await self.cache.get(cache_key)
        if cached:
            return cached
        entity = await self.repository.get(EnterpriseEntity1, entity_id, tenant_id)
        if entity:
            await self.cache.set(cache_key, entity.to_dict(), expire=3600)
        return entity

    async def process_complex_business_logic_1(self, entity: EnterpriseEntity1):
        # 10 years of legacy business rules
        await asyncio.sleep(0.01)
        if getattr(entity, f'attribute_1') == 'legacy_value_1':
            logger.warning(f'Handling legacy edge case from 2018 for attribute 1')
            setattr(entity, f'attribute_1', 'migrated_value_1')
